import{_ as l,o as i,c as e,a2 as t}from"./chunks/framework.Crpw6aS5.js";const q=JSON.parse('{"title":"2006年巴菲特致股东信核心总结","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/2006年/核心总结.md","filePath":"01_letters/2006年/核心总结.md"}'),o={name:"01_letters/2006年/核心总结.md"};function r(h,a,n,u,s,d){return i(),e("div",null,[...a[0]||(a[0]=[t('<h1 id="_2006年巴菲特致股东信核心总结" tabindex="-1">2006年巴菲特致股东信核心总结 <a class="header-anchor" href="#_2006年巴菲特致股东信核心总结" aria-label="Permalink to &quot;2006年巴菲特致股东信核心总结&quot;">​</a></h1><h2 id="业绩表现" tabindex="-1">业绩表现 <a class="header-anchor" href="#业绩表现" aria-label="Permalink to &quot;业绩表现&quot;">​</a></h2><ul><li>净资产增加169亿美元，每股账面价值增长18.4%</li><li>这是美国企业史上年度净资产增长的纪录（不含并购）</li><li>42年复合增长率21.4%</li></ul><h2 id="主要投资决策" tabindex="-1">主要投资决策 <a class="header-anchor" href="#主要投资决策" aria-label="Permalink to &quot;主要投资决策&quot;">​</a></h2><h3 id="重大收购" tabindex="-1">重大收购 <a class="header-anchor" href="#重大收购" aria-label="Permalink to &quot;重大收购&quot;">​</a></h3><ol><li><p><strong>ISCAR（以色列）</strong>：40亿美元收购80%股份</p><ul><li>首次海外重大收购</li><li>切削工具制造商，61个国家业务</li><li>&quot;伯克希尔的股东很幸运能与Eitan、Jacob、Danny和他们才华横溢的同事们合作&quot;</li></ul></li><li><p><strong>TTI</strong>：电子元器件分销商，年销售额13亿美元</p><ul><li>创始人Paul Andrews为员工寻找永久归宿</li></ul></li></ol><h3 id="投资组合变化" tabindex="-1">投资组合变化 <a class="header-anchor" href="#投资组合变化" aria-label="Permalink to &quot;投资组合变化&quot;">​</a></h3><ul><li>中国石油：4.88亿美元买入，获利40亿美元卖出</li><li>外汇合约实现总收益22亿美元</li><li>新建仓康菲石油、强生、浦项制铁、特易购</li></ul><h2 id="关键理念" tabindex="-1">关键理念 <a class="header-anchor" href="#关键理念" aria-label="Permalink to &quot;关键理念&quot;">​</a></h2><h3 id="衡量标准" tabindex="-1">衡量标准 <a class="header-anchor" href="#衡量标准" aria-label="Permalink to &quot;衡量标准&quot;">​</a></h3><ul><li><strong>每股投资</strong>：80,636美元，复合增长27.5%</li><li><strong>每股非保险收益</strong>：3,625美元，复合增长31.7%</li><li>规模增长使未来难以复制过去业绩</li></ul><h3 id="equitas交易" tabindex="-1">Equitas交易 <a class="header-anchor" href="#equitas交易" aria-label="Permalink to &quot;Equitas交易&quot;">​</a></h3><ul><li>劳合社历史债务重组</li><li>71亿美元保费换取139亿美元限额保障</li><li>展示伯克希尔承担长期独特风险的能力</li></ul><h3 id="货币与贸易" tabindex="-1">货币与贸易 <a class="header-anchor" href="#货币与贸易" aria-label="Permalink to &quot;货币与贸易&quot;">​</a></h3><ul><li>美国贸易赤字7,600亿美元</li><li>投资收入账户转为负值——&quot;我们用完了银行账户，转向了信用卡&quot;</li><li>预测政治反弹不可避免</li></ul><h2 id="保险业务" tabindex="-1">保险业务 <a class="header-anchor" href="#保险业务" aria-label="Permalink to &quot;保险业务&quot;">​</a></h2><ul><li>浮存金509亿美元，承保利润38亿美元</li><li>连续两年实现承保盈利</li><li>预警：2007年保险业利润率将下降</li></ul><h3 id="关键保险经理人" tabindex="-1">关键保险经理人 <a class="header-anchor" href="#关键保险经理人" aria-label="Permalink to &quot;关键保险经理人&quot;">​</a></h3><ul><li>Tony Nicely（GEICO）：市场份额从2.5%增至7.7%</li><li>Ajit Jain：创造独特再保险模式</li><li>Joe Brandon &amp; Tad Montross：完成General Re整改</li></ul><h2 id="管理理念" tabindex="-1">管理理念 <a class="header-anchor" href="#管理理念" aria-label="Permalink to &quot;管理理念&quot;">​</a></h2><h3 id="继任计划" tabindex="-1">继任计划 <a class="header-anchor" href="#继任计划" aria-label="Permalink to &quot;继任计划&quot;">​</a></h3><ul><li>三位CEO候选人确定</li><li>寻找投资继任人：年轻、独立思考、情绪稳定、基因上厌恶风险</li></ul><h3 id="董事会改革" tabindex="-1">董事会改革 <a class="header-anchor" href="#董事会改革" aria-label="Permalink to &quot;董事会改革&quot;">​</a></h3><ul><li>新董事Susan Decker加入</li><li>董事标准：所有者导向、商业头脑、有兴趣、真正独立</li></ul><h3 id="慈善捐赠" tabindex="-1">慈善捐赠 <a class="header-anchor" href="#慈善捐赠" aria-label="Permalink to &quot;慈善捐赠&quot;">​</a></h3><ul><li>宣布将大部分伯克希尔股份捐给五个基金会</li><li>25年内分配完毕，不追求永久基金会</li></ul><h2 id="经典语录" tabindex="-1">经典语录 <a class="header-anchor" href="#经典语录" aria-label="Permalink to &quot;经典语录&quot;">​</a></h2><blockquote><p>&quot;在寻找收购对象时，我们采用老人的策略：我们忽略小老鼠，将收购精力集中在更大的猎物上。&quot;</p></blockquote><blockquote><p>&quot;有效的CEO薪酬安排应该与特定CEO有权影响的运营成果挂钩，而不是与股价波动相关。&quot;</p></blockquote><blockquote><p>&quot;巨大的资金会自己铸造锚索。&quot;</p></blockquote><hr><p><em>生成日期：2026年4月</em></p>',32)])])}const b=l(o,[["render",r]]);export{q as __pageData,b as default};
